import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as o,e as c}from"./app-0014a839.js";const t="/408CSFamily/assets/栈的基本结构-10aae5bf.png",d={},i=c('<h1 id="栈的基本概念和基本操作" tabindex="-1"><a class="header-anchor" href="#栈的基本概念和基本操作" aria-hidden="true">#</a> 栈的基本概念和基本操作</h1><h2 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h2><p><code>栈</code>： 只允许在一端进行插入或者删除操作的<strong>线性表</strong>，<code>后进先出的线性表</code>。</p><ul><li>明确栈是一种线性表</li><li>限定栈只能在某一端进行插入或者删除操作</li></ul><figure><img src="'+t+'" alt="栈的顺序结构" tabindex="0" loading="lazy"><figcaption>栈的顺序结构</figcaption></figure><p><code>栈顶</code>：线性表允许进行插入和删除的一端。</p><p><code>栈底</code>：不允许进行插入和删除的另外一端，是<strong>固定的</strong>。类似杯底这中概念</p><p><code>空栈</code>：不含任何元素的空表，也叫<strong>栈空</strong></p><p>基本结构如下：</p><p>在上面的基本结构中，可以假设存在栈S=(a1,a2,a3,a4,a5,a6,a7,a8),很明显</p><ul><li>栈顶元素：a1</li><li>栈底元素：a8</li></ul><p>栈只能在栈顶进行插入和删除操作</p><ul><li>进栈顺序：a1-&gt;a2-&gt;a3-&gt;a4-&gt;a5-&gt;a6-&gt;a7-&gt;a8</li><li>出栈顺序：a8-&gt;a7-&gt;a6-&gt;a5-&gt;a4-&gt;a3-&gt;a2-&gt;a1</li></ul><p>可以得出结论：栈是后进先出（先进后出），即：LIFO（Last In First Out），也可以叫<strong>后进先出的线性表</strong></p><h2 id="基本操作" tabindex="-1"><a class="header-anchor" href="#基本操作" aria-hidden="true">#</a> 基本操作</h2><ul><li><code>InitStack(&amp;S)</code>: 初始化一个空栈<code>S</code>，栈顶指针初始化为-1</li><li><code>StackEmpty(S)</code>: 判断一个栈是否为空，如果栈空则返回<code>true</code>,否则返回<code>false</code></li><li><code>Push(&amp;S,x)</code>: 进栈，若栈未满，<code>x</code>进栈操作，插入到栈内成为<code>新的栈顶元素</code>。</li><li><code>Pop(&amp;S,&amp;x)</code>: 出栈，若栈非空，出栈操作，<strong>弹出栈顶元素</strong>，用指针<code>x</code>进行返回。</li><li><code>GetTop(S,&amp;x)</code>: 读栈顶元素，若栈<code>S</code>非空，用x返回栈顶元素。</li><li><code>ClearStack(&amp;S)</code>: 销毁栈，释放栈<code>S</code>占用的存储空间。</li></ul><blockquote><p>Tips: <code>&amp;</code>是C++特有的，可以用来表示引用调用，类似<code>传址目的</code>，可以类比指针。 当然，在C语言中*代表指针，指向存储地址，也是具有<code>传址目的</code></p></blockquote>',17),l=[i];function s(r,n){return a(),o("div",null,l)}const h=e(d,[["render",s],["__file","stack-basic-concepts.html.vue"]]);export{h as default};
